6	//! Host-side loading for embedded device artifact bundles.
7	
8	use crate::ltoir;
9	pub use cuda_core::embedded::{
10	    ArtifactCompileOptions, ArtifactPayloadKind, EmbeddedModule, OwnedArtifactBundle,
11	    artifact_bundles_from_binary_path, artifact_bundles_from_current_exe,
12	    embedded_modules_from_current_exe,
13	};
14	use cuda_core::{CudaContext, CudaModule, DriverError};
15	use std::sync::Arc;
16	use thiserror::Error;
17	
18	/// Errors while discovering, building, or loading an embedded CUDA module.
19	#[derive(Debug, Error)]
20	pub enum EmbeddedModuleError {
21	    /// Reading the embedded artifact section failed.
22	    #[error(transparent)]
23	    Core(#[from] cuda_core::EmbeddedModuleError),
24	
25	    /// The named bundle was not present in the current executable.
26	    #[error("embedded CUDA module '{name}' was not found")]
27	    ModuleNotFound { name: String },
28	
29	    /// No embedded bundles with loadable payloads were found.
30	    #[error("no embedded CUDA modules were found")]
31	    NoModules,
32	
33	    /// A bundle existed, but it contained no supported payload.
34	    #[error("embedded CUDA module '{name}' has no supported payload")]
35	    UnsupportedPayload { name: String },
36	
37	    /// NVVM IR or LTOIR payload compilation failed.
38	    #[error("failed to build embedded CUDA module: {0}")]
39	    Ltoir(#[from] ltoir::LtoirError),
40	
41	    /// The CUDA driver rejected the selected module image.
42	    #[error("failed to load embedded CUDA module: {0}")]
43	    Driver(#[from] DriverError),
44	}
45	
46	/// Load a named embedded artifact bundle from the current executable.
47	///
48	/// Cubin and PTX payloads are loaded directly with the CUDA driver. NVVM IR and
49	/// LTOIR payloads are linked to an in-memory cubin for their original target.
50	/// A payload built for a standard pre-Blackwell target, such as `sm_86`, may
51	/// instead be converted to PTX and JIT-compiled by the driver on Blackwell.
52	pub fn load_embedded_module(
53	    ctx: &Arc<CudaContext>,
54	    name: &str,
55	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
56	    let bundle = artifact_bundles_from_current_exe()?
57	        .into_iter()
58	        .find(|bundle| bundle.name == name)
59	        .ok_or_else(|| EmbeddedModuleError::ModuleNotFound {
60	            name: name.to_string(),
61	        })?;
62	    load_bundle(ctx, &bundle)
63	}
64	
65	/// Merge all PTX bundles from the current executable into a single CUDA module.
66	///
67	/// When a generic kernel is monomorphized in a consuming crate, its PTX ends
68	/// up in that crate's bundle rather than the defining crate's bundle. This
69	/// function gathers every PTX bundle in the binary, strips duplicate header
70	/// directives (`.version`, `.target`, `.address_size`) from all but the first
71	/// bundle, concatenates the bodies, and loads the result as one CUDA module.
72	/// All kernel symbols are therefore available regardless of which crate bundle
73	/// they were compiled into.
74	///
75	/// Bundles with non-PTX payloads (NVVM IR, LTOIR, cubin) are skipped; use
76	/// `load_embedded_module` for those.
77	pub fn load_all_ptx_bundles_merged(
78	    ctx: &Arc<CudaContext>,
79	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
80	    let bundles = artifact_bundles_from_current_exe()?;
81	
82	    let mut merged = String::new();
83	    let mut found_any = false;
84	
85	    for bundle in &bundles {
86	        if let Some(ptx_bytes) = bundle.payload(ArtifactPayloadKind::Ptx) {
87	            let ptx_str = std::str::from_utf8(ptx_bytes)
88	                .map_err(|_| EmbeddedModuleError::UnsupportedPayload {
89	                    name: bundle.name.clone(),
90	                })?
91	                .trim_end_matches('\0');
92	
93	            if !found_any {
94	                merged.push_str(ptx_str);
95	                merged.push('\n');
96	                found_any = true;
97	            } else {
98	                // Strip per-file header directives; only one set is valid in a
99	                // concatenated PTX module.
100	                for line in ptx_str.lines() {
101	                    let trimmed = line.trim_start();
102	                    if trimmed.starts_with(".version")
103	                        || trimmed.starts_with(".target")
104	                        || trimmed.starts_with(".address_size")
105	                    {
106	                        continue;
107	                    }
108	                    merged.push_str(line);
109	                    merged.push('\n');
110	                }
111	            }
112	        }
113	    }
114	
115	    if !found_any {
116	        return Err(EmbeddedModuleError::NoModules);
117	    }
118	
119	    Ok(ctx.load_module_from_image(merged.as_bytes())?)
120	}
121	
122	/// Load the first embedded artifact bundle with a supported payload.
123	pub fn load_first_embedded_module(
124	    ctx: &Arc<CudaContext>,
125	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
126	    for bundle in artifact_bundles_from_current_exe()? {
127	        match load_bundle(ctx, &bundle) {
128	            Ok(module) => return Ok(module),
129	            Err(EmbeddedModuleError::UnsupportedPayload { .. }) => continue,
130	            Err(error) => return Err(error),
131	        }
132	    }
133	    Err(EmbeddedModuleError::NoModules)
134	}
135	
136	fn load_bundle(
137	    ctx: &Arc<CudaContext>,
138	    bundle: &OwnedArtifactBundle,
139	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
140	    if let Some(cubin) = bundle.payload(ArtifactPayloadKind::Cubin) {
141	        return Ok(ctx.load_module_from_image(cubin)?);
142	    }
143	
144	    if let Some(ptx) = bundle.payload(ArtifactPayloadKind::Ptx) {
145	        return Ok(ctx.load_module_from_image(ptx)?);
146	    }
147	
148	    if let Some(nvvm_ir) = bundle.payload(ArtifactPayloadKind::NvvmIr) {
149	        let emitted = target_arch_for_bundle(bundle)?;
150	        let execution = ltoir::execution_arch_for_context(ctx)?;
151	        let allow_fma_contraction = bundle.compile_options.fma_contraction_enabled();
152	        let image = match ltoir::execution_route(&emitted, &execution)? {
153	            ltoir::ExecutionRoute::Cubin => ltoir::build_cubin_from_nvvm_ir_with_options(
154	                nvvm_ir,
155	                &bundle.name,
156	                &emitted.sm(),
157	                allow_fma_contraction,
158	            )?,
159	            ltoir::ExecutionRoute::PtxBridge => ltoir::build_ptx_from_nvvm_ir_with_options(
160	                nvvm_ir,
161	                &bundle.name,
162	                &emitted.sm(),
163	                allow_fma_contraction,
164	            )?,
165	        };
166	        return Ok(ctx.load_module_from_image(&image)?);
167	    }
168	
169	    if let Some(ltoir) = bundle.payload(ArtifactPayloadKind::Ltoir) {
170	        let emitted = target_arch_for_bundle(bundle)?;
171	        let execution = ltoir::execution_arch_for_context(ctx)?;
172	        let allow_fma_contraction = bundle.compile_options.fma_contraction_enabled();
173	        let image = match ltoir::execution_route(&emitted, &execution)? {
174	            ltoir::ExecutionRoute::Cubin => ltoir::link_ltoir_to_cubin_with_options(
175	                ltoir,
176	                &bundle.name,
177	                &emitted.sm(),
178	                allow_fma_contraction,
179	            )?,
180	            ltoir::ExecutionRoute::PtxBridge => ltoir::link_ltoir_to_ptx_with_options(
181	                ltoir,
182	                &bundle.name,
183	                &emitted.sm(),
184	                allow_fma_contraction,
185	            )?,
186	        };
187	        return Ok(ctx.load_module_from_image(&image)?);
188	    }
189	
190	    Err(EmbeddedModuleError::UnsupportedPayload {
191	        name: bundle.name.clone(),
192	    })
193	}
194	
195	fn target_arch_for_bundle(
196	    bundle: &OwnedArtifactBundle,
197	) -> Result<libnvvm_sys::CudaArch, ltoir::LtoirError> {
198	    let explicit = std::env::var("CUDA_OXIDE_TARGET").ok();
199	    target_arch_for_bundle_with_explicit(bundle, explicit.as_deref())
200	}
201	
202	fn target_arch_for_bundle_with_explicit(
203	    bundle: &OwnedArtifactBundle,
204	    explicit_target: Option<&str>,
205	) -> Result<libnvvm_sys::CudaArch, ltoir::LtoirError> {
206	    ltoir::resolve_source_target(concrete_bundle_target(&bundle.target)?, explicit_target)
207	}
208	
209	fn concrete_bundle_target(
210	    target: &str,
211	) -> Result<Option<libnvvm_sys::CudaArch>, ltoir::LtoirError> {
212	    match target {
213	        // Compatibility for artifacts emitted before concrete NVVM targets
214	        // were recorded. New bundles must never use these sentinels.
215	        "libdevice" | "nvvm-ir" => Ok(None),
216	        target => Ok(Some(target.parse()?)),
217	    }
218	}
219	
220	#[cfg(test)]
221	mod tests {
222	    use super::*;
223	
224	    fn bundle_with_target(target: &str) -> OwnedArtifactBundle {
225	        OwnedArtifactBundle {
226	            name: "demo".to_string(),
227	            target: target.to_string(),
228	            compile_options: ArtifactCompileOptions::new(),
229	            payloads: Vec::new(),
230	            entries: Vec::new(),
231	        }
232	    }
233	
234	    #[test]
235	    fn target_arch_uses_bundle_sm_target() {
236	        assert_eq!(
237	            concrete_bundle_target("sm_90")
238	                .unwrap()
239	                .map(|target| target.sm()),
240	            Some("sm_90".to_string())
241	        );
242	    }
243	
244	    #[test]
245	    fn target_arch_uses_bundle_compute_target() {
246	        assert_eq!(
247	            concrete_bundle_target("compute_90")
248	                .unwrap()
249	                .map(|target| target.sm()),
250	            Some("sm_90".to_string())
251	        );
252	    }
253	
254	    #[test]
255	    fn target_arch_falls_back_for_non_arch_target() {
256	        // Older bundles used these names instead of recording a concrete
257	        // architecture. New bundles always record a validated `sm_*` target.
258	        for legacy in ["libdevice", "nvvm-ir"] {
259	            assert_eq!(concrete_bundle_target(legacy).unwrap(), None);
260	        }
261	    }
262	
263	    #[test]
264	    fn legacy_bundle_without_recorded_target_requires_explicit_target() {
265	        for sentinel in ["libdevice", "nvvm-ir"] {
266	            let bundle = bundle_with_target(sentinel);
267	            let error = target_arch_for_bundle_with_explicit(&bundle, None)
268	                .expect_err("the original build target is required");
269	            assert!(matches!(error, ltoir::LtoirError::TargetNotFound));
270	
271	            let asserted =
272	                target_arch_for_bundle_with_explicit(&bundle, Some("compute_86")).unwrap();
273	            assert_eq!(asserted.sm(), "sm_86");
274	        }
275	    }
276	
277	    #[test]
278	    fn recorded_bundle_target_overrides_explicit_environment_target() {
279	        let bundle = bundle_with_target("sm_90");
280	        let selected = target_arch_for_bundle_with_explicit(&bundle, Some("sm_120")).unwrap();
281	        assert_eq!(selected.sm(), "sm_90");
282	    }
283	
284	    #[test]
285	    fn target_arch_rejects_malformed_bundle_target() {
286	        assert!(concrete_bundle_target("sm_90x").is_err());
287	    }
288	}
