5	
6	//! Loading CUDA modules from embedded device artifact bundles.
7	
8	use crate::{CudaContext, CudaModule, DriverError};
9	use oxide_artifacts::ArtifactError;
10	pub use oxide_artifacts::{
11	    ArtifactCompileOptions, ArtifactPayloadKind, COMPILE_OPTIONS_TARGET_MARKER, OwnedArtifactBundle,
12	};
13	use std::fmt;
14	use std::path::{Path, PathBuf};
15	use std::sync::Arc;
16	
17	#[derive(Clone, Debug, PartialEq, Eq)]
18	pub struct EmbeddedModule {
19	    bundle: OwnedArtifactBundle,
20	}
21	
22	impl EmbeddedModule {
23	    pub fn new(bundle: OwnedArtifactBundle) -> Option<Self> {
24	        loadable_payload(&bundle)
25	            .is_some()
26	            .then_some(Self { bundle })
27	    }
28	
29	    pub fn name(&self) -> &str {
30	        &self.bundle.name
31	    }
32	
33	    pub fn target(&self) -> &str {
34	        &self.bundle.target
35	    }
36	
37	    pub fn bundle(&self) -> &OwnedArtifactBundle {
38	        &self.bundle
39	    }
40	
41	    pub fn payload(&self, kind: ArtifactPayloadKind) -> Option<&[u8]> {
42	        self.bundle.payload(kind)
43	    }
44	
45	    pub fn load(&self, ctx: &Arc<CudaContext>) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
46	        let image =
47	            loadable_payload(&self.bundle).expect("EmbeddedModule always has a loadable payload");
48	        ctx.load_module_from_image(image)
49	            .map_err(EmbeddedModuleError::Driver)
50	    }
51	}
52	
53	pub fn artifact_bundles_from_current_exe() -> Result<Vec<OwnedArtifactBundle>, EmbeddedModuleError>
54	{
55	    let path =
56	        std::env::current_exe().map_err(|source| EmbeddedModuleError::CurrentExe { source })?;
57	    artifact_bundles_from_binary_path(path)
58	}
59	
60	pub fn artifact_bundles_from_binary_path(
61	    path: impl AsRef<Path>,
62	) -> Result<Vec<OwnedArtifactBundle>, EmbeddedModuleError> {
63	    let path = path.as_ref();
64	    let bytes = std::fs::read(path).map_err(|source| EmbeddedModuleError::Io {
65	        path: path.to_path_buf(),
66	        source,
67	    })?;
