383	pub fn build_artifact_blob(spec: &ArtifactBundleSpec<'_>) -> Result<Vec<u8>, ArtifactError> {
384	    validate_spec(spec)?;
385	
386	    let mut out = vec![0; HEADER_BYTES];
387	    push_bytes(&mut out, spec.name.as_bytes());
388	    push_bytes(&mut out, spec.target.as_bytes());
389	
390	    let payload_record_start = out.len();
391	    out.resize(out.len() + spec.payloads.len() * PAYLOAD_RECORD_BYTES, 0);
392	    let entry_record_start = out.len();
393	    out.resize(out.len() + spec.entries.len() * ENTRY_RECORD_BYTES, 0);
394	
395	    for (index, payload) in spec.payloads.iter().enumerate() {
396	        let name_offset = checked_u32(out.len(), "payload name offset")?;
397	        push_bytes(&mut out, payload.name.as_bytes());
398	        align_vec(&mut out, 8);
399	        let data_offset = checked_u32(out.len(), "payload data offset")?;
400	        push_bytes(&mut out, payload.bytes);
401	        align_vec(&mut out, 8);
402	
403	        let record = payload_record_start + index * PAYLOAD_RECORD_BYTES;
404	        write_u16(&mut out, record, payload.kind.to_u16());
405	        write_u16(&mut out, record + 2, 0);
406	        write_u32(&mut out, record + 4, data_offset);
407	        write_u32(
408	            &mut out,
409	            record + 8,
410	            checked_u32(payload.bytes.len(), "payload length")?,
411	        );
412	        write_u32(&mut out, record + 12, name_offset);
413	        write_u16(
414	            &mut out,
415	            record + 16,
416	            checked_u16(payload.name.len(), "payload name length")?,
417	        );
418	    }
419	
420	    for (index, entry) in spec.entries.iter().enumerate() {
421	        let symbol_offset = checked_u32(out.len(), "entry symbol offset")?;
422	        push_bytes(&mut out, entry.symbol.as_bytes());
423	        align_vec(&mut out, 8);
424	
425	        let record = entry_record_start + index * ENTRY_RECORD_BYTES;
426	        write_u16(&mut out, record, entry.kind.to_u16());
427	        write_u16(&mut out, record + 2, u16::from(entry.metadata.is_some()));
428	        write_u64(&mut out, record + 4, entry.metadata.unwrap_or(0));
429	        write_u32(&mut out, record + 12, symbol_offset);
430	        write_u16(
431	            &mut out,
432	            record + 16,
433	            checked_u16(entry.symbol.len(), "entry symbol length")?,
434	        );
435	    }
436	
437	    let total_len = checked_u32(out.len(), "total length")?;
438	    out[0..8].copy_from_slice(&ARTIFACT_MAGIC);
439	    // Keep default-policy bundles on v1 for backward compatibility. A bundle
440	    // that carries required compile policy uses v2 so an older reader rejects
441	    // it instead of silently ignoring the semantic flag.
442	    let version = if spec.compile_options == ArtifactCompileOptions::new() {
443	        LEGACY_ARTIFACT_VERSION
444	    } else {
445	        ARTIFACT_VERSION
446	    };
447	    write_u16(&mut out, 8, version);
448	    write_u16(&mut out, 10, HEADER_BYTES as u16);
449	    write_u32(&mut out, 12, total_len);
450	    write_u16(&mut out, 16, checked_u16(spec.name.len(), "name length")?);
451	    write_u16(
452	        &mut out,
453	        18,
454	        checked_u16(spec.target.len(), "target length")?,
455	    );
456	    write_u16(
457	        &mut out,
458	        20,
459	        checked_u16(spec.payloads.len(), "payload count")?,
460	    );
461	    write_u16(
462	        &mut out,
463	        22,
464	        checked_u16(spec.entries.len(), "entry count")?,
465	    );
466	    write_u64(&mut out, 24, spec.compile_options.bits());
467	
468	    Ok(out)
469	}
