587	pub fn artifact_blob_total_len(bytes: &[u8]) -> Result<usize, ArtifactError> {
588	    require_len(bytes, HEADER_BYTES, "header")?;
589	    if bytes[0..8] != ARTIFACT_MAGIC {
590	        return Err(ArtifactError::BadMagic);
591	    }
592	    let total_len = read_u32(bytes, 12)? as usize;
593	    if total_len < HEADER_BYTES {
594	        return Err(ArtifactError::Malformed(format!(
595	            "embedded artifact length {total_len} is smaller than the header"
596	        )));
597	    }
598	    if total_len > bytes.len() {
599	        return Err(ArtifactError::Truncated("blob"));
600	    }
601	    Ok(total_len)
602	}
