627	/// Wrap an artifact section blob in a relocatable host object file.
628	///
629	/// The object contains a single `.oxart` data section. When
630	/// `anchor_symbol` is given, a global symbol with that name is defined at
631	/// the start of the section. The anchor matters for *library* crates:
632	/// their artifact object becomes a member of an `.rlib` archive, and a
633	/// linker only extracts an archive member when the member defines a
634	/// symbol that resolves an outstanding undefined reference. Without a
635	/// defined symbol the member is silently skipped and the bundle never
636	/// reaches the final binary. Host-side code (the `#[cuda_module]` macro)
637	/// emits a matching reference to the anchor to force the extraction.
638	/// `SHF_GNU_RETAIN` on the section additionally protects it from
639	/// `--gc-sections` once the member has been linked in.
640	#[cfg(feature = "object-write")]
641	pub fn build_host_object_for_target(
642	    section_data: &[u8],
643	    target: &str,
644	    anchor_symbol: Option<&str>,
645	) -> Result<Vec<u8>, ArtifactError> {
646	    if section_data.is_empty() {
647	        return Err(ArtifactError::EmptyPayload);
648	    }
649	
650	    match anchor_symbol {
651	        Some(anchor_symbol) => build_host_object_with_section(
652	            ARTIFACT_SECTION_NAME,
653	            section_data,
654	            target,
655	            &[(anchor_symbol, false)],
656	        ),
657	        None => build_host_object_with_section(ARTIFACT_SECTION_NAME, section_data, target, &[]),
658	    }
659	}
