825	fn checked_u16(value: usize, field: &'static str) -> Result<u16, ArtifactError> {
826	    u16::try_from(value).map_err(|_| ArtifactError::TooLarge(field))
827	}
828	
829	fn checked_u32(value: usize, field: &'static str) -> Result<u32, ArtifactError> {
830	    u32::try_from(value).map_err(|_| ArtifactError::TooLarge(field))
831	}
