844	fn read_slice<'a>(
845	    bytes: &'a [u8],
846	    offset: usize,
847	    len: usize,
848	    field: &'static str,
849	) -> Result<&'a [u8], ArtifactError> {
850	    let end = offset
851	        .checked_add(len)
852	        .ok_or(ArtifactError::TooLarge(field))?;
853	    bytes
854	        .get(offset..end)
855	        .ok_or(ArtifactError::Truncated(field))
856	}
857	
858	fn read_str<'a>(
859	    bytes: &'a [u8],
860	    offset: usize,
861	    len: usize,
862	    field: &'static str,
863	) -> Result<&'a str, ArtifactError> {
864	    let bytes = read_slice(bytes, offset, len, field)?;
865	    core::str::from_utf8(bytes).map_err(|_| ArtifactError::InvalidUtf8(field))
866	}
867	
868	fn require_len(bytes: &[u8], len: usize, field: &'static str) -> Result<(), ArtifactError> {
869	    if bytes.len() < len {
870	        Err(ArtifactError::Truncated(field))
871	    } else {
872	        Ok(())
873	    }
874	}
875	
876	fn read_u16(bytes: &[u8], offset: usize) -> Result<u16, ArtifactError> {
877	    let bytes = read_slice(bytes, offset, 2, "u16")?;
878	    Ok(u16::from_le_bytes([bytes[0], bytes[1]]))
879	}
880	
881	fn read_u32(bytes: &[u8], offset: usize) -> Result<u32, ArtifactError> {
882	    let bytes = read_slice(bytes, offset, 4, "u32")?;
883	    Ok(u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]))
884	}
885	
886	fn read_u64(bytes: &[u8], offset: usize) -> Result<u64, ArtifactError> {
887	    let bytes = read_slice(bytes, offset, 8, "u64")?;
888	    Ok(u64::from_le_bytes([
889	        bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
890	    ]))
891	}
892	
893	fn write_u16(out: &mut [u8], offset: usize, value: u16) {
894	    out[offset..offset + 2].copy_from_slice(&value.to_le_bytes());
895	}
896	
897	fn write_u32(out: &mut [u8], offset: usize, value: u32) {
898	    out[offset..offset + 4].copy_from_slice(&value.to_le_bytes());
899	}
900	
901	fn write_u64(out: &mut [u8], offset: usize, value: u64) {
902	    out[offset..offset + 8].copy_from_slice(&value.to_le_bytes());
903	}
