fn generic_contract_brand_and_prepare_witness_keep_specialization_type() {
    let module: ItemMod = parse_quote! {
        mod kernels {
            #[kernel]
            #[launch_bounds(128)]
            #[launch_contract(domain = 1, dynamic_shared = 0)]
